dslRule:
/*!id: jdt-remove-redundant-fieldbinding-cast*/
/*!description: Remove redundant (FieldBinding) cast when the expression is already known to be of that type.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, performance*/
(org.eclipse.jdt.internal.compiler.lookup.FieldBinding) $expression :: subtypeOf($expression, "org.eclipse.jdt.internal.compiler.lookup.FieldBinding")
=> $expression
;;

dslRuleAfterChange:
if ($expression instanceof org.eclipse.jdt.internal.compiler.ast.TextBlock) {
    return convert((org.eclipse.jdt.internal.compiler.ast.TextBlock) $expression);
}
=>
if ($expression instanceof org.eclipse.jdt.internal.compiler.ast.TextBlock $textBlock) {
    return convert($textBlock);
}
;;

dslRule:
/* This is a RED transformation. The current TriggerPattern DSL lacks the capability to structurally modify an 'if' statement's condition (e.g., adding a pattern variable to an InstanceofExpression) while preserving its body. It also lacks a mechanism to dynamically generate suitable variable names from types. The addition of 'ModuleBinding' specific logic is new functionality, not a refactoring. */
// Example of the desired pattern and a hypothetical replacement, if the DSL supported it:
// if ($expr instanceof $Type)
// => if ($expr instanceof $Type $derivedName($Type)) /* where $derivedName is a hypothetical function to create a variable name from $Type */
// ;;

dslRuleAfterChange:
/* Hypothetical rule if DSL extensions were available */
@id: java16.patternmatching.instanceof
@severity: info
if ($expr instanceof $Type) :: sourceVersionGE(16)
=> if ($expr instanceof $Type $derivedName($Type)) /* $derivedName is a hypothetical DSL function to generate a variable name (e.g., 'tb' for TypeBinding) */
;;

// Example of a desired DSL rule if structural rewrite was supported:
// if ($node instanceof $Type) { $Type $var = ($Type) $node; $body$ }
// => if ($node instanceof $Type $var) { $body$ }
// This syntax is purely illustrative and not supported by the current DSL.

dslRule:
/*!id: jdt.internal.astmatcher.typepattern.getpatternvariable-to-getpatternvariable2*/
/*!description: Modernize ASTMatcher logic for TypePattern to use getPatternVariable2() for JLS22+ to reflect API evolution.*/
/*!severity: info*/
/*!minJavaVersion: 16*/
safeSubtreeMatch($node.getPatternVariable(), $o.getPatternVariable()) :: instanceof($node, "org.eclipse.jdt.core.dom.TypePattern") && instanceof($o, "org.eclipse.jdt.core.dom.TypePattern") && sourceVersionGE(22)
=> safeSubtreeMatch($node.getPatternVariable2(), $o.getPatternVariable2())
;;

/*!id: jdt.internal.astmatcher.typepattern.getpatternvariable-to-getpatternvariable2*/
/*!description: Modernize ASTMatcher logic for TypePattern to use getPatternVariable2() for JLS22+ to reflect API evolution.*/
/*!severity: info*/
/*!minJavaVersion: 16*/
safeSubtreeMatch($node.getPatternVariable(), $o.getPatternVariable()) :: instanceof($node, "org.eclipse.jdt.core.dom.TypePattern") && instanceof($o, "org.eclipse.jdt.core.dom.TypePattern") && sourceVersionGE(22)
=> safeSubtreeMatch($node.getPatternVariable2(), $o.getPatternVariable2())
;;
